import stylesText from './health-meals.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import { formatMacro } from '../../../../utils/format-macro.js';
import {
    HEALTH_EVENTS,
    type AddIngredientEvent,
    type FoodLogBackEvent,
    type SelectLibraryItemEvent,
    type SelectOffItemEvent,
} from '../../health-events.js';
import {
    computeSnapshotMacros,
    type FoodItem,
    type MealWithIngredients,
    type NewMealWithIngredients,
} from '@motivation/shared';
import { HealthService } from '../../../../services/health.service.js';
import { createComponentLogger } from '../../../../utils/component-logger.js';
import '../../food-log/food-log.component.js';
import type { FoodLog } from '../../food-log/food-log.component.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="meals-container">
        <div id="list-view">
            <div class="toolbar">
                <button class="btn-primary" id="new-meal-btn" type="button">+ New meal</button>
            </div>
            <div class="meals-list" id="meals-list"></div>
        </div>
        <div id="picker-view" hidden>
            <div class="picker-header">
                <button class="btn-secondary" id="picker-back-btn" type="button">← Back to meal</button>
                <span class="picker-title" id="picker-title">Add ingredient</span>
            </div>
            <food-log id="picker-food-log"></food-log>
        </div>
    </div>
`;

const mealCardTemplate = document.createElement('template');
mealCardTemplate.innerHTML = `
    <details class="meal-card">
        <summary>
            <span class="meal-summary-name"></span>
            <span class="meal-summary-meta"></span>
            <span class="meal-summary-cal"></span>
        </summary>
        <div class="meal-body">
            <div>
                <label for="name">Name</label>
                <input type="text" data-field="name">
            </div>
            <div>
                <label for="notes">Notes</label>
                <textarea data-field="notes"></textarea>
            </div>
            <div class="scale-row">
                <label>Default scale</label>
                <input type="number" data-field="default-scale" min="0.1" step="0.1">
            </div>
            <label>Ingredients</label>
            <ul class="ingredient-list" data-role="ingredient-list"></ul>
            <button class="btn-secondary" data-action="add-ingredient" type="button">+ Add ingredient</button>
            <div class="actions" data-role="actions"></div>
        </div>
    </details>
`;

const ingredientRowTemplate = document.createElement('template');
ingredientRowTemplate.innerHTML = `
    <li class="ingredient-row">
        <span class="name" data-role="name"></span>
        <input type="number" data-role="amount" min="0.1" step="0.1">
        <span class="unit" data-role="unit"></span>
        <button class="remove" data-action="remove" type="button">×</button>
    </li>
`;

interface DraftIngredient {
    food_item: FoodItem;
    amount: number;
}

interface MealDraft {
    /** Existing server id; absent for an in-progress new meal. */
    id?: string;
    name: string;
    notes: string;
    default_scale: number;
    ingredients: DraftIngredient[];
    /** Used to keep DOM nodes stable across renders. */
    key: string;
}

interface PickerSession {
    draftKey: string;
    /** When set, the picker replaces this index; otherwise it appends. */
    editingIndex: number | null;
}

export class HealthMeals extends HTMLElement {
    private listEl: HTMLElement | null = null;
    private listView: HTMLElement | null = null;
    private pickerView: HTMLElement | null = null;
    private foodLog: FoodLog | null = null;
    private pickerSession: PickerSession | null = null;
    private drafts: MealDraft[] = [];
    private focusValue: string | null = null;
    private readonly log = createComponentLogger('health-meals');

    /** Server id of a meal to expand-and-scroll-into-view after the next render. */
    set focus(value: string | null) {
        this.focusValue = value;
        if (this.listEl) this.applyFocus();
    }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        this.listView = shadow.getElementById('list-view');
        this.listEl = shadow.getElementById('meals-list');
        this.pickerView = shadow.getElementById('picker-view');
        this.foodLog = shadow.getElementById('picker-food-log') as FoodLog;
        this.foodLog.mode = 'add-ingredient';

        shadow.getElementById('new-meal-btn')!.addEventListener('click', () => this.startNewMeal());
        shadow.getElementById('picker-back-btn')!.addEventListener('click', () => this.cancelPicker());

        this.wirePickerEvents(this.foodLog);
        this.setStatus('Loading meals…');
        void this.load();
    }

    /** Public reload — useful for tests and after external mutations. */
    async reload(): Promise<void> {
        return this.load();
    }

    private wirePickerEvents(foodLog: FoodLog): void {
        // SELECT_LIBRARY_ITEM and SELECT_OFF_ITEM bubble out of the search results;
        // we own the screen state here so we drive the food-log directly without
        // a navigation roundtrip.
        foodLog.addEventListener(HEALTH_EVENTS.SELECT_LIBRARY_ITEM, (event: SelectLibraryItemEvent) => {
            event.stopPropagation();
            void foodLog.showLibraryItem(event.detail);
        });
        foodLog.addEventListener(HEALTH_EVENTS.SELECT_OFF_ITEM, (event: SelectOffItemEvent) => {
            event.stopPropagation();
            foodLog.showProduct(event.detail);
        });
        foodLog.addEventListener(HEALTH_EVENTS.FOOD_LOG_BACK, (_event: FoodLogBackEvent) => {
            // Detail's own back button → return to the picker's search view.
            foodLog.showSearchView();
        });
        foodLog.addEventListener(HEALTH_EVENTS.ADD_INGREDIENT, (event: AddIngredientEvent) => {
            event.stopPropagation();
            this.commitPickerResult(event.detail.food_item, event.detail.amount);
        });
    }

    private async load(): Promise<void> {
        try {
            const summaries = await HealthService.listMeals();
            const detailed = await Promise.all(summaries.map((m) => HealthService.fetchMeal(m.id)));
            this.drafts = detailed.map((m) => this.draftFromMeal(m));
            this.renderList();
        } catch (err) {
            this.setError(err);
        }
    }

    private setStatus(text: string): void {
        if (!this.listEl) return;
        this.listEl.replaceChildren();
        const div = document.createElement('div');
        div.className = 'empty-state';
        div.textContent = text;
        this.listEl.appendChild(div);
    }

    private setError(err: unknown): void {
        if (!this.listEl) return;
        this.log.error('Meal load failed', err);
        this.listEl.replaceChildren();
        const pre = document.createElement('pre');
        pre.className = 'screen-error';
        pre.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
        this.listEl.appendChild(pre);
    }

    private renderList(): void {
        if (!this.listEl) return;
        this.listEl.replaceChildren();
        if (this.drafts.length === 0) {
            this.setStatus('No meals yet. Tap "+ New meal" to create one.');
            return;
        }
        const fragment = document.createDocumentFragment();
        for (const draft of this.drafts) {
            fragment.appendChild(this.renderMealCard(draft));
        }
        this.listEl.appendChild(fragment);
        this.applyFocus();
    }

    /**
     * If a `focus` id was set (e.g. from `/health/meals?focus=<id>`), open that
     * meal's <details> and scroll it into view. Other cards stay in their
     * default closed state. Called after each renderList.
     */
    private applyFocus(): void {
        if (!this.focusValue || !this.listEl) return;
        const card = this.listEl.querySelector(`details[data-draft-key="id-${CSS.escape(this.focusValue)}"]`) as HTMLDetailsElement | null;
        if (!card) return;
        card.open = true;
        card.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }

    private renderMealCard(draft: MealDraft): HTMLElement {
        const card = mealCardTemplate.content.cloneNode(true) as DocumentFragment;
        const details = card.querySelector('details') as HTMLDetailsElement;
        details.dataset.draftKey = draft.key;
        if (!draft.id) details.open = true;

        this.applySummary(details, draft);

        const nameInput = details.querySelector('[data-field="name"]') as HTMLInputElement;
        nameInput.value = draft.name;
        nameInput.addEventListener('input', () => {
            draft.name = nameInput.value;
            this.applySummary(details, draft);
        });

        const notesInput = details.querySelector('[data-field="notes"]') as HTMLTextAreaElement;
        notesInput.value = draft.notes;
        notesInput.addEventListener('input', () => { draft.notes = notesInput.value; });

        const scaleInput = details.querySelector('[data-field="default-scale"]') as HTMLInputElement;
        scaleInput.value = String(draft.default_scale);
        scaleInput.addEventListener('input', () => {
            const n = Number.parseFloat(scaleInput.value);
            if (Number.isFinite(n) && n > 0) {
                draft.default_scale = n;
                this.applySummary(details, draft);
            }
        });

        const ingredientList = details.querySelector('[data-role="ingredient-list"]') as HTMLElement;
        this.renderIngredientList(ingredientList, draft);

        const addBtn = details.querySelector('[data-action="add-ingredient"]') as HTMLButtonElement;
        addBtn.addEventListener('click', () => this.openPickerForDraft(draft));

        const actions = details.querySelector('[data-role="actions"]') as HTMLElement;
        this.populateCardActions(actions, draft);

        return details;
    }

    private populateCardActions(host: HTMLElement, draft: MealDraft): void {
        host.replaceChildren();
        if (draft.id) {
            const deleteBtn = document.createElement('button');
            deleteBtn.type = 'button';
            deleteBtn.className = 'btn-secondary btn-danger';
            deleteBtn.textContent = 'Delete';
            deleteBtn.addEventListener('click', () => void this.handleDelete(draft));
            host.appendChild(deleteBtn);
        } else {
            const cancelBtn = document.createElement('button');
            cancelBtn.type = 'button';
            cancelBtn.className = 'btn-secondary';
            cancelBtn.textContent = 'Cancel';
            cancelBtn.addEventListener('click', () => {
                this.drafts = this.drafts.filter((d) => d.key !== draft.key);
                this.renderList();
            });
            host.appendChild(cancelBtn);
        }

        const saveBtn = document.createElement('button');
        saveBtn.type = 'button';
        saveBtn.className = 'btn-primary';
        saveBtn.textContent = draft.id ? 'Save changes' : 'Create meal';
        saveBtn.addEventListener('click', () => void this.handleSave(draft));
        host.appendChild(saveBtn);
    }

    private renderIngredientList(list: HTMLElement, draft: MealDraft): void {
        list.replaceChildren();
        for (const [index, ing] of draft.ingredients.entries()) {
            const node = ingredientRowTemplate.content.cloneNode(true) as DocumentFragment;
            const li = node.querySelector('li') as HTMLLIElement;

            const name = li.querySelector('[data-role="name"]') as HTMLElement;
            name.textContent = ing.food_item.display_name;
            // Click the name to edit this ingredient via the full food-log picker.
            name.style.cursor = 'pointer';
            name.title = 'Edit this ingredient';
            name.addEventListener('click', () => this.openPickerForDraft(draft, index));

            const amountInput = li.querySelector('[data-role="amount"]') as HTMLInputElement;
            amountInput.value = String(ing.amount);
            amountInput.addEventListener('input', () => {
                const n = Number.parseFloat(amountInput.value);
                if (Number.isFinite(n) && n > 0) {
                    draft.ingredients[index].amount = n;
                    this.refreshSummaryByKey(draft.key);
                }
            });

            const unit = li.querySelector('[data-role="unit"]') as HTMLElement;
            unit.textContent = ing.food_item.base_unit;

            const removeBtn = li.querySelector('[data-action="remove"]') as HTMLButtonElement;
            removeBtn.addEventListener('click', () => {
                draft.ingredients.splice(index, 1);
                this.renderIngredientList(list, draft);
                this.refreshSummaryByKey(draft.key);
            });

            list.appendChild(li);
        }
    }

    private applySummary(details: HTMLDetailsElement, draft: MealDraft): void {
        const name = details.querySelector('.meal-summary-name') as HTMLElement;
        const meta = details.querySelector('.meal-summary-meta') as HTMLElement;
        const cal = details.querySelector('.meal-summary-cal') as HTMLElement;
        name.textContent = draft.name || '(unnamed meal)';
        meta.textContent = `${draft.ingredients.length} item${draft.ingredients.length === 1 ? '' : 's'}`;
        cal.textContent = `${formatMacro(this.totalCalories(draft))} kcal`;
    }

    private refreshSummaryByKey(key: string): void {
        if (!this.listEl) return;
        const card = this.listEl.querySelector(`details[data-draft-key="${key}"]`) as HTMLDetailsElement | null;
        const draft = this.drafts.find((d) => d.key === key);
        if (card && draft) this.applySummary(card, draft);
    }

    private openPickerForDraft(draft: MealDraft, editingIndex: number | null = null): void {
        if (!this.foodLog || !this.listView || !this.pickerView) return;
        this.pickerSession = { draftKey: draft.key, editingIndex };
        const titleEl = this.shadowRoot!.getElementById('picker-title')!;
        titleEl.textContent = editingIndex === null ? 'Add ingredient' : 'Edit ingredient';

        if (editingIndex !== null) {
            const ing = draft.ingredients[editingIndex];
            void this.foodLog.showLibraryItem(ing.food_item, ing.amount);
        } else {
            this.foodLog.showSearchView();
        }
        this.listView.hidden = true;
        this.pickerView.hidden = false;
    }

    private cancelPicker(): void {
        this.pickerSession = null;
        if (this.listView) this.listView.hidden = false;
        if (this.pickerView) this.pickerView.hidden = true;
    }

    private commitPickerResult(food: FoodItem, amount: number): void {
        const session = this.pickerSession;
        if (!session) {
            this.cancelPicker();
            return;
        }
        const draft = this.drafts.find((d) => d.key === session.draftKey);
        if (!draft) {
            this.cancelPicker();
            return;
        }
        if (session.editingIndex === null) {
            draft.ingredients.push({ food_item: food, amount });
        } else {
            draft.ingredients[session.editingIndex] = { food_item: food, amount };
        }
        this.cancelPicker();
        this.renderList();
        this.openCardByKey(draft.key);
    }

    private openCardByKey(key: string): void {
        if (!this.listEl) return;
        const card = this.listEl.querySelector(`details[data-draft-key="${key}"]`) as HTMLDetailsElement | null;
        if (card) card.open = true;
    }

    private async handleSave(draft: MealDraft): Promise<void> {
        if (!draft.name.trim()) {
            alert('Meal name is required');
            return;
        }
        if (draft.ingredients.length === 0) {
            alert('Add at least one ingredient');
            return;
        }
        const payload: NewMealWithIngredients = {
            name: draft.name.trim(),
            notes: draft.notes.trim() || undefined,
            default_scale: draft.default_scale,
            ingredients: draft.ingredients.map((i) => ({ food_item_id: i.food_item.id, amount: i.amount })),
        };
        try {
            if (draft.id) {
                await HealthService.updateMeal(draft.id, payload);
            } else {
                await HealthService.createMeal(payload);
            }
            await this.load();
        } catch (err) {
            this.setError(err);
        }
    }

    private async handleDelete(draft: MealDraft): Promise<void> {
        if (!draft.id) return;
        if (!confirm(`Delete "${draft.name}"? This cannot be undone.`)) return;
        try {
            await HealthService.deleteMeal(draft.id);
            await this.load();
        } catch (err) {
            this.setError(err);
        }
    }

    private startNewMeal(): void {
        const draft: MealDraft = {
            name: '',
            notes: '',
            default_scale: 1.0,
            ingredients: [],
            key: `new-${crypto.randomUUID()}`,
        };
        this.drafts = [draft, ...this.drafts];
        this.renderList();
    }

    private draftFromMeal(meal: MealWithIngredients): MealDraft {
        return {
            id: meal.id,
            name: meal.name,
            notes: meal.notes ?? '',
            default_scale: meal.default_scale,
            ingredients: meal.ingredients.map((i) => ({ food_item: i.food_item, amount: i.amount })),
            key: `id-${meal.id}`,
        };
    }

    private totalCalories(draft: MealDraft): number {
        let total = 0;
        for (const ing of draft.ingredients) {
            const macros = computeSnapshotMacros(ing.food_item, ing.amount * draft.default_scale);
            total += macros.calories ?? 0;
        }
        return total;
    }
}

if (!customElements.get('health-meals')) {
    customElements.define('health-meals', HealthMeals);
}
