import { buildSectionPage } from '../../../utils/section-page.utils.js';
import type { ScreenComponent } from '../../../types/screen-component.js';
import './health-meals/health-meals.component.js';
import type { HealthMeals } from './health-meals/health-meals.component.js';

export class HealthMealsScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private meals: HealthMeals | null = null;
    private queryValue: URLSearchParams | null = null;

    setLoading(): void {}
    setError(): void {}
    clearStatus(): void {}

    set query(value: URLSearchParams | null) {
        this.queryValue = value;
        this.applyFocusFromQuery();
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Health · Meals', 'health', '/health');
        this.meals = document.createElement('health-meals') as HealthMeals;
        page.content.appendChild(this.meals);
        this.applyFocusFromQuery();
    }

    private applyFocusFromQuery(): void {
        if (!this.meals) return;
        const focus = this.queryValue?.get('focus') ?? null;
        this.meals.focus = focus;
    }
}

if (!customElements.get('health-meals-screen')) {
    customElements.define('health-meals-screen', HealthMealsScreen);
}
